func newCodeOwners(workingDir string) (*codeownerInfo, error) {
	r, err := findCodeOwnersFile(workingDir)
	if err != nil || r == nil {
		return nil, err
	}

	owners, err := codeowners.FromReader(r, workingDir)
	if err != nil {
		return nil, err
	}

	return &codeownerInfo{owners: owners}, nil
}
